import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

scope = "/subscriptions/<subscription-id>"
budget_name = "monthly-prod-budget"
url = (
    f"https://management.azure.com{scope}/"
    f"providers/Microsoft.Consumption/budgets/{budget_name}"
    f"?api-version=2023-11-01"
)

budget_body = {
    "properties": {
        "category": "Cost",
        "amount": 5000,
        "timeGrain": "Monthly",
        "timePeriod": {
            "startDate": "2024-01-01",
            "endDate": "2099-12-31"
        },
        "notifications": {
            "Actual_GT_80": {
                "enabled": True,
                "operator": "GreaterThan",
                "threshold": 80,
                "thresholdType": "Actual",
                "contactEmails": ["finance@contoso.com", "cloudops@contoso.com"]
            },
            "Actual_GT_90": {
                "enabled": True,
                "operator": "GreaterThan",
                "threshold": 90,
                "thresholdType": "Actual",
                "contactEmails": ["finance-lead@contoso.com"]
            },
            "Forecasted_GT_100": {
                "enabled": True,
                "operator": "GreaterThan",
                "threshold": 100,
                "thresholdType": "Forecasted",
                "contactEmails": ["engineering-vp@contoso.com"],
                "contactGroups": [
                    "/subscriptions/<subscription-id>/resourceGroups/<rg>/providers/microsoft.insights/actionGroups/budget-overflow-ag"
                ]
            }
        }
    }
}

resp = requests.put(url, headers=headers, json=budget_body)
print(resp.status_code, resp.json().get("name"))

