import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

subscription_id = "<subscription-id>"
rg_name = "billing-ops-rg"
ag_name = "budget-overflow-ag"

url = (
    f"https://management.azure.com/subscriptions/{subscription_id}/"
    f"resourceGroups/{rg_name}/"
    f"providers/microsoft.insights/actionGroups/{ag_name}"
    f"?api-version=2023-09-01-preview"
)

ag_body = {
    "location": "global",
    "properties": {
        "groupShortName": "BudgetOvfl",
        "enabled": True,
        "emailReceivers": [
            {
                "name": "Finance Lead",
                "emailAddress": "finance-lead@contoso.com",
                "useCommonAlertSchema": True
            }
        ],
        "webhookReceivers": [
            {
                "name": "BudgetSlack",
                "serviceUri": "https://hooks.slack.com/services/xxx/yyy/zzz",
                "useCommonAlertSchema": True
            }
        ],
        "automationRunbookReceivers": [
            {
                "name": "StopDevVMs",
                "automationAccountId": (
                    f"/subscriptions/{subscription_id}/"
                    f"resourceGroups/automation-rg/"
                    f"providers/Microsoft.Automation/automationAccounts/contoso-automation"
                ),
                "runbookName": "Stop-NonProdVMs",
                "webhookResourceId": (
                    f"/subscriptions/{subscription_id}/"
                    f"resourceGroups/automation-rg/"
                    f"providers/Microsoft.Automation/automationAccounts/contoso-automation/"
                    f"webhooks/BudgetAlert-StopVMs"
                ),
                "isGlobalRunbook": False,
                "useCommonAlertSchema": True
            }
        ]
    }
}

resp = requests.put(url, headers=headers, json=ag_body)
print(f"Action Group created: {resp.status_code} — {resp.json().get('name')}")
print(f"Action Group ID: {resp.json().get('id')}")

# variables.tf
variable "subscription_id" {
  type        = string
  description = "Azure subscription ID"
}

variable "budget_amount" {
  type        = number
  default     = 5000
  description = "Monthly budget limit in USD"
}

variable "alert_emails" {
  type        = list(string)
  default     = ["cloud-ops@contoso.com"]
}

# main.tf
resource "azurerm_consumption_budget_subscription" "monthly" {
  name            = "monthly-subscription-budget"
  subscription_id = "/subscriptions/${var.subscription_id}"
  amount          = var.budget_amount
  time_grain      = "Monthly"

  time_period {
    start_date = "2024-01-01T00:00:00Z"
    end_date   = "2099-12-01T00:00:00Z"
  }

  notification {
    operator  = "GreaterThan"
    threshold = 80
    threshold_type = "Actual"
    enabled   = true
    contact_emails = var.alert_emails
  }

  notification {
    operator  = "GreaterThan"
    threshold = 100
    threshold_type = "Forecasted"
    enabled   = true
    contact_emails = var.alert_emails
  }
}

# Resource group scoped budget
resource "azurerm_consumption_budget_resource_group" "per_rg" {
  for_each          = toset(["production-rg", "platform-rg", "data-rg"])
  name              = "${each.key}-budget"
  resource_group_id = "/subscriptions/${var.subscription_id}/resourceGroups/${each.key}"
  amount            = var.budget_amount / 3
  time_grain        = "Monthly"

  time_period {
    start_date = "2024-01-01T00:00:00Z"
    end_date   = "2099-12-01T00:00:00Z"
  }

  notification {
    operator       = "GreaterThan"
    threshold      = 90
    threshold_type = "Actual"
    enabled        = true
    contact_emails = var.alert_emails
  }
}

output "budget_ids" {
  value = {
    subscription = azurerm_consumption_budget_subscription.monthly.id
    resource_groups = {
      for k, v in azurerm_consumption_budget_resource_group.per_rg : k => v.id
    }
  }
}
